// package-lock.json generation script

const fs = require('fs');
const path = require('path');
const npmLs = require('npm-ls');

function generateLockFile() {
  // Get the current working directory
  const cwd = process.cwd();

  // Get the package.json file
  const pkgJsonPath = path.join(cwd, 'package.json');
  const pkgJson = JSON.parse(fs.readFileSync(pkgJsonPath, 'utf8'));

  // Get the dependencies from package.json
  const dependencies = pkgJson.dependencies;

  // Create a new lock file object
  const lockFile = {
    name: pkgJson.name,
    version: pkgJson.version,
    dependencies: {}
  };

  // Iterate over the dependencies and generate the lock file
  Object.keys(dependencies).forEach((dependency) => {
    const dependencyVersion = dependencies[dependency];
    const packageInfo = npmLs(dependency);
    if (packageInfo) {
      lockFile.dependencies[dependency] = {
        version: dependencyVersion,
        integrity: packageInfo.integrity
      };
    }
  });

  // Write the lock file to disk
  const lockFilePath = path.join(cwd, 'package-lock.json');
  fs.writeFileSync(lockFilePath, JSON.stringify(lockFile, null, 2));
}

// Usage:
generateLockFile();